import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface CryptocurrencyData {
  name: string;
  symbol: string;
  currentPrice: number;
  '24hChange': number;
  '24hChangePercent': number;
}

interface MiniPriceChart {
  time: string;
  price: number;
}

interface CryptoData {
  cryptocurrency: CryptocurrencyData;
  miniPriceChart: MiniPriceChart[];
}

export default function Widget() {
  const cryptoData = response.data as CryptoData;
  const { cryptocurrency, miniPriceChart } = cryptoData;
  const isPositive = cryptocurrency['24hChange'] >= 0;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#B0BEC5', mb: 0.5 }}>
              {cryptocurrency.name} ({cryptocurrency.symbol})
            </Typography>
            <Typography variant="h4" sx={{ color: '#FFFFFF', fontWeight: 600 }}>
              ${cryptocurrency.currentPrice.toLocaleString()}
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5} sx={{ mt: 0.5 }}>
              {isPositive ? <TrendingUp sx={{ fontSize: 16, color: '#4CAF50' }} /> : <TrendingDown sx={{ fontSize: 16, color: '#F44336' }} />}
              <Typography variant="body2" sx={{ color: isPositive ? '#4CAF50' : '#F44336' }}>
                ${Math.abs(cryptocurrency['24hChange']).toFixed(2)} ({cryptocurrency['24hChangePercent'].toFixed(2)}%)
              </Typography>
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 150 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: miniPriceChart.map((point) => point.price),
                  color: isPositive ? '#4CAF50' : '#F44336',
                  label: 'Price',
                  curve: 'linear',
                }
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: miniPriceChart.map((point) => point.time),
                  id: 'times',
                }
              ]}
              yAxis={[{ id: 'prices' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="times"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="prices"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
